import{_ as s,o as a,c as p,a2 as l}from"./chunks/framework.DvFsUg-r.js";const u=JSON.parse('{"title":"CAT-21. 국제 업무 & 무역","description":"","frontmatter":{"outline":[2,3]},"headers":[],"relativePath":"hermes/benchmark/international-business.md","filePath":"hermes/benchmark/international-business.md","lastUpdated":1781092690000}'),i={name:"hermes/benchmark/international-business.md"};function e(c,n,t,o,r,h){return a(),p("div",null,[...n[0]||(n[0]=[l(`<h1 id="cat-21-국제-업무-무역" tabindex="-1">CAT-21. 국제 업무 &amp; 무역 <a class="header-anchor" href="#cat-21-국제-업무-무역" aria-label="Permalink to &quot;CAT-21. 국제 업무 &amp; 무역&quot;">​</a></h1><blockquote><p><strong>평가 핵심</strong>: 에이전트가 해외 바이어 대응, 무역 서류, 현지화, 해외 진출 전략 등 <strong>글로벌 비즈니스 실무</strong>를 처리할 수 있는가?</p></blockquote><hr><h2 id="ib-01-해외-바이어-커뮤니케이션" tabindex="-1">IB-01. 해외 바이어 커뮤니케이션 ⭐⭐ <a class="header-anchor" href="#ib-01-해외-바이어-커뮤니케이션" aria-label="Permalink to &quot;IB-01. 해외 바이어 커뮤니케이션 :star::star:&quot;">​</a></h2><h3 id="프롬프트" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>아래 3가지 상황의 해외 바이어 대응 이메일을 영문으로 작성해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>우리 회사: 한국 화장품 제조사 &quot;K-Glow&quot;</span></span>
<span class="line"><span>제품: 비건 스킨케어 라인 (세럼, 토너, 크림)</span></span>
<span class="line"><span>현재 수출: 일본, 동남아 5개국</span></span>
<span class="line"><span></span></span>
<span class="line"><span>상황 1: 신규 바이어 첫 인콰이어리 응답</span></span>
<span class="line"><span>- 바이어: 독일 유기농 화장품 유통사 &quot;NaturHaus&quot;</span></span>
<span class="line"><span>- 문의: 제품 카탈로그, 가격표, MOQ, 샘플 요청</span></span>
<span class="line"><span>- 우리 목표: 유럽 시장 진출의 교두보</span></span>
<span class="line"><span>- 포함: 회사 소개, EU 인증 현황 (CPNP 등록 완료), </span></span>
<span class="line"><span>  샘플 발송 제안, 미팅 제안</span></span>
<span class="line"><span></span></span>
<span class="line"><span>상황 2: 클레임 대응</span></span>
<span class="line"><span>- 바이어: 일본 기존 거래처 &quot;Sakura Beauty&quot;</span></span>
<span class="line"><span>- 클레임: 최근 선적분에서 세럼 100병 중 5병 라벨 인쇄 불량</span></span>
<span class="line"><span>- 우리 대응: 사과 + 대체품 발송 + 원인 분석 + 재발 방지</span></span>
<span class="line"><span></span></span>
<span class="line"><span>상황 3: 가격 인상 통보</span></span>
<span class="line"><span>- 바이어: 베트남 최대 거래처 &quot;VietBeauty&quot; (연 거래 5억원)</span></span>
<span class="line"><span>- 내용: 원자재 가격 상승으로 다음 분기부터 5% 인상 필요</span></span>
<span class="line"><span>- 어려움: 거래 3년차, 관계 유지 중요</span></span>
<span class="line"><span>- 보완: 연간 계약 시 3% 인상으로 조정 가능 제안</span></span>
<span class="line"><span></span></span>
<span class="line"><span>각 이메일:</span></span>
<span class="line"><span>- Subject line</span></span>
<span class="line"><span>- 인사 (바이어 문화 고려)</span></span>
<span class="line"><span>- 본문 (명확하고 프로페셔널)</span></span>
<span class="line"><span>- 클로징 (다음 단계 명시)</span></span>
<span class="line"><span>- 각 이메일에 한국어 해설 (왜 이렇게 썼는지)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>파일: \`international/buyer-email-collection.md\`</span></span></code></pre></div><h3 id="평가-포인트" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 영문 비즈니스 이메일의 프로페셔널 수준</li><li>[ ] 독일 바이어: 직접적이고 체계적인 톤</li><li>[ ] 일본 바이어: 정중함, 사과의 깊이</li><li>[ ] 베트남 바이어: 관계 유지 + 가격 인상의 균형</li><li>[ ] EU 인증(CPNP) 관련 지식의 정확성</li><li>[ ] Subject line의 명확성</li><li>[ ] 문화별 톤 차별화</li></ul><hr><h2 id="ib-02-수출-서류-세트" tabindex="-1">IB-02. 수출 서류 세트 ⭐⭐ <a class="header-anchor" href="#ib-02-수출-서류-세트" aria-label="Permalink to &quot;IB-02. 수출 서류 세트 :star::star:&quot;">​</a></h2><h3 id="프롬프트-1" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-1" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>수출 거래에 필요한 서류 세트를 작성해줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>거래 조건:</span></span>
<span class="line"><span>- 수출자: K-Glow (한국)</span></span>
<span class="line"><span>- 수입자: NaturHaus GmbH (독일 프랑크푸르트)</span></span>
<span class="line"><span>- 제품: 비건 세럼 5,000병 (300ml, 단가 USD 8.00)</span></span>
<span class="line"><span>- 총 금액: USD 40,000</span></span>
<span class="line"><span>- 인코텀즈: CIF Hamburg</span></span>
<span class="line"><span>- 결제: L/C at sight (일람불 신용장)</span></span>
<span class="line"><span>- 선적: 부산항 → 함부르크항 (해상, 약 30일)</span></span>
<span class="line"><span>- 보험: 수출자 부담 (CIF 조건)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. \`international/commercial-invoice.md\` — 상업 송장</span></span>
<span class="line"><span>   - 발행인, 수취인 정보</span></span>
<span class="line"><span>   - 품명, 수량, 단가, 금액</span></span>
<span class="line"><span>   - 인코텀즈, 원산지, HS Code</span></span>
<span class="line"><span>   - 결제 조건</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. \`international/packing-list.md\` — 포장 명세서</span></span>
<span class="line"><span>   - 카톤 수, 개당 수량, 총 수량</span></span>
<span class="line"><span>   - 순중량, 총중량, 용적</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. \`international/bill-of-lading-guide.md\` — B/L 작성 가이드</span></span>
<span class="line"><span>   - 선하증권 각 항목 설명</span></span>
<span class="line"><span>   - Shipper, Consignee, Notify Party 작성 기준</span></span>
<span class="line"><span>   - Original B/L vs Surrendered B/L 차이</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. \`international/certificate-of-origin.md\` — 원산지 증명서 가이드</span></span>
<span class="line"><span>   - FTA 활용 (한-EU FTA)</span></span>
<span class="line"><span>   - 원산지 결정 기준</span></span>
<span class="line"><span>   - 관세 혜택 계산</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. \`international/export-checklist.md\` — 수출 절차 체크리스트</span></span>
<span class="line"><span>   - 계약 체결 → L/C 수취 → 생산 → 검사 → </span></span>
<span class="line"><span>     통관 → 선적 → 서류 네고 → 대금 회수</span></span>
<span class="line"><span>   - 각 단계별 필요 서류, 담당 기관, 소요 기간</span></span>
<span class="line"><span>   - 주의사항 (L/C 불일치 사유 TOP 10)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>파일 경로: 위에 명시된 대로.</span></span>
<span class="line"><span>면책: 실제 법적 효력은 관세사/법률가 검토 필요.</span></span></code></pre></div><h3 id="평가-포인트-1" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-1" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 상업 송장의 형식 정확성</li><li>[ ] HS Code의 합리적 추정</li><li>[ ] CIF 조건의 정확한 이해</li><li>[ ] B/L 작성 가이드의 실무적 유용성</li><li>[ ] 한-EU FTA 원산지 기준의 정확성</li><li>[ ] L/C 불일치 사유의 현실성</li><li>[ ] 전체 수출 절차의 포괄성</li></ul><hr><h2 id="ib-03-해외-시장-진출-전략" tabindex="-1">IB-03. 해외 시장 진출 전략 ⭐⭐⭐ <a class="header-anchor" href="#ib-03-해외-시장-진출-전략" aria-label="Permalink to &quot;IB-03. 해외 시장 진출 전략 :star::star::star:&quot;">​</a></h2><h3 id="프롬프트-2" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-2" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>일본 시장 진출 전략서를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>회사: &quot;팀플로우&quot; — 프로젝트 관리 SaaS (한국 MAU 5,000)</span></span>
<span class="line"><span>진출 목표: 12개월 내 일본 유료 고객 100사</span></span>
<span class="line"><span>예산: 5억원</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물: \`international/japan-market-entry-strategy.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 시장 분석</span></span>
<span class="line"><span>   - 일본 프로젝트 관리 SaaS 시장 규모 &amp; 성장률</span></span>
<span class="line"><span>   - 주요 경쟁사 (Backlog, Redmine, Asana Japan, Monday.com)</span></span>
<span class="line"><span>   - 일본 기업의 SaaS 도입 특성 (온프레미스 선호, 보안 민감)</span></span>
<span class="line"><span>   - 한국 SaaS의 일본 진출 사례 (성공/실패)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 제품 현지화 로드맵</span></span>
<span class="line"><span>   - 언어: 일본어 UI/UX (단순 번역이 아닌 현지화)</span></span>
<span class="line"><span>   - 기능: 일본 특수 요구 (한코 결재, 일본식 조직 구조)</span></span>
<span class="line"><span>   - 보안: ISMAP(일본 정부 클라우드 인증) 취득 필요성</span></span>
<span class="line"><span>   - 결제: 엔화 결제, 청구서 발행 (일본 상관행)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. Go-to-Market 전략</span></span>
<span class="line"><span>   - 진입 방식: 직접 진출 vs 파트너 vs 에이전트</span></span>
<span class="line"><span>   - 추천: SI 파트너 2~3사 확보 + 자체 마케팅 병행</span></span>
<span class="line"><span>   - 타깃 세그먼트: IT 기업 → 제조업 → 대기업 순</span></span>
<span class="line"><span>   - 가격: 한국 대비 1.5~2배 (일본 시장 가격 수준)</span></span>
<span class="line"><span>   - 마케팅: 일본 전시회 (IT Week Japan), 웹 세미나, SEO</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 조직 &amp; 인력</span></span>
<span class="line"><span>   - 일본 법인 설립 vs 한국 본사 운영</span></span>
<span class="line"><span>   - 필요 인력: 현지 영업 2, CS 1, 마케팅 1</span></span>
<span class="line"><span>   - 채용: 현지 채용 vs 한국인 주재원</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 재무 계획 (12개월)</span></span>
<span class="line"><span>   - 투자: 법인 설립, 현지화 개발, 마케팅, 인건비</span></span>
<span class="line"><span>   - 수익: 100사 × ARPU 15만엔/월 = 월 1,500만엔</span></span>
<span class="line"><span>   - BEP 시점 예상</span></span>
<span class="line"><span>   - 리스크 시나리오 (50사 vs 100사 vs 150사)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. 리스크 &amp; 대응</span></span>
<span class="line"><span>   - 문화 차이 (의사결정 속도, 관계 구축)</span></span>
<span class="line"><span>   - 환율 리스크</span></span>
<span class="line"><span>   - 경쟁 심화</span></span>
<span class="line"><span>   - 현지 규제 (개인정보보호, ISMAP)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>7. 실행 타임라인</span></span>
<span class="line"><span>   - Q1: 현지화 개발 + 파트너 발굴</span></span>
<span class="line"><span>   - Q2: 베타 출시 + 전시회</span></span>
<span class="line"><span>   - Q3: 정식 출시 + 영업 본격화</span></span>
<span class="line"><span>   - Q4: 100사 달성 + 시리즈 검토</span></span></code></pre></div><h3 id="평가-포인트-2" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-2" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 일본 SaaS 시장의 특수성 이해 (온프레미스 선호)</li><li>[ ] 현지화의 깊이 (UI 번역 아닌 한코 결재 등)</li><li>[ ] ISMAP 인증 필요성 인식</li><li>[ ] SI 파트너 전략의 일본 현실 반영</li><li>[ ] 가격 전략의 합리성 (한국 대비 프리미엄)</li><li>[ ] 문화 차이 리스크의 구체성</li><li>[ ] 12개월 타임라인의 현실성</li></ul><hr><h2 id="ib-04-다국어-제품-카탈로그" tabindex="-1">IB-04. 다국어 제품 카탈로그 ⭐⭐ <a class="header-anchor" href="#ib-04-다국어-제품-카탈로그" aria-label="Permalink to &quot;IB-04. 다국어 제품 카탈로그 :star::star:&quot;">​</a></h2><h3 id="프롬프트-3" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-3" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>수출용 제품 카탈로그를 영문/일문/중문 3개 언어로 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>제품: 한국 전통차 브랜드 &quot;다원(DaWon)&quot;</span></span>
<span class="line"><span>- 제품 6종: 녹차, 보이차, 유자차, 대추차, 쌍화차, 현미녹차</span></span>
<span class="line"><span>- 타깃: 해외 식품 바이어 (수입업자, 유통사)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. \`international/product-catalog-en.md\` — 영문 카탈로그</span></span>
<span class="line"><span>2. \`international/product-catalog-ja.md\` — 일문 카탈로그</span></span>
<span class="line"><span>3. \`international/product-catalog-zh.md\` — 중문 카탈로그</span></span>
<span class="line"><span></span></span>
<span class="line"><span>각 카탈로그 구성:</span></span>
<span class="line"><span>- 브랜드 스토리 (한국 전통차의 역사, 우리 브랜드의 차별점)</span></span>
<span class="line"><span>- 제품별 페이지:</span></span>
<span class="line"><span>  - 제품명 (현지화된 이름)</span></span>
<span class="line"><span>  - 제품 설명 (맛, 향, 건강 효능)</span></span>
<span class="line"><span>  - 원재료 &amp; 원산지</span></span>
<span class="line"><span>  - 규격 (용량, 포장 단위)</span></span>
<span class="line"><span>  - 보관 방법</span></span>
<span class="line"><span>  - 인증: HACCP, 유기농 (해당 제품만), Halal (보유 시)</span></span>
<span class="line"><span>- MOQ, 리드타임, 결제 조건</span></span>
<span class="line"><span>- 연락처</span></span>
<span class="line"><span></span></span>
<span class="line"><span>현지화 주의점:</span></span>
<span class="line"><span>- 영문: 건강 효능 표현 시 FDA 규정 고려 (과대광고 방지)</span></span>
<span class="line"><span>- 일문: 정중한 경어체, 일본 소비자 선호 키워드 (안심, 자연)</span></span>
<span class="line"><span>- 중문: 간체자, 중국 시장 선호 포인트 (한류, 프리미엄 이미지)</span></span>
<span class="line"><span>- 각 언어별 &quot;이 문화권에서 어필하는 포인트&quot; 해설</span></span>
<span class="line"><span></span></span>
<span class="line"><span>추가: \`international/localization-notes.md\`</span></span>
<span class="line"><span>- 3개 언어 번역 시 주요 판단과 이유</span></span>
<span class="line"><span>- 문화적으로 주의한 표현 (금기어, 오해 가능 표현)</span></span>
<span class="line"><span>- 제품명 현지화 근거</span></span></code></pre></div><h3 id="평가-포인트-3" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-3" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 3개 언어의 자연스러운 품질</li><li>[ ] FDA 규정 고려한 영문 건강 표현</li><li>[ ] 일본 경어체의 정확성</li><li>[ ] 중문 간체자 사용</li><li>[ ] 문화별 어필 포인트 차별화</li><li>[ ] 제품명 현지화의 적절성 (유자차→Yuzu Tea 등)</li><li>[ ] 현지화 노트의 유용성</li></ul><hr><h2 id="ib-05-해외-법인-설립-가이드" tabindex="-1">IB-05. 해외 법인 설립 가이드 ⭐⭐⭐ <a class="header-anchor" href="#ib-05-해외-법인-설립-가이드" aria-label="Permalink to &quot;IB-05. 해외 법인 설립 가이드 :star::star::star:&quot;">​</a></h2><h3 id="프롬프트-4" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-4" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>베트남 법인 설립 가이드를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>배경:</span></span>
<span class="line"><span>- 우리: 한국 SW 개발사 (직원 50명)</span></span>
<span class="line"><span>- 목적: 베트남 오프쇼어 개발센터 설립 (초기 10명)</span></span>
<span class="line"><span>- 예산: 초기 설립 3억원</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물: \`international/vietnam-entity-setup-guide.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 법인 유형 비교</span></span>
<span class="line"><span>   - 100% 외국인 투자법인 vs 합작법인 vs 지사</span></span>
<span class="line"><span>   - 각 유형: 장단점, 필요 자본금, 설립 기간</span></span>
<span class="line"><span>   - 추천 및 근거</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 설립 절차 (Step by Step)</span></span>
<span class="line"><span>   - 투자등록증(IRC) 취득</span></span>
<span class="line"><span>   - 기업등록증(ERC) 취득</span></span>
<span class="line"><span>   - 인감 제작</span></span>
<span class="line"><span>   - 은행 계좌 개설</span></span>
<span class="line"><span>   - 세무 등록</span></span>
<span class="line"><span>   - 각 단계: 필요 서류, 소요 기간, 비용, 담당 기관</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 사무실 &amp; 인프라</span></span>
<span class="line"><span>   - 하노이 vs 호치민 vs 다낭 비교</span></span>
<span class="line"><span>   - 오피스 형태 (서비스 오피스, 코워킹, 독립 사무실)</span></span>
<span class="line"><span>   - 월 임대료 범위</span></span>
<span class="line"><span>   - 인터넷/인프라 수준</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 인력 운영</span></span>
<span class="line"><span>   - 베트남 IT 개발자 시장 (연봉 범위, 기술 수준)</span></span>
<span class="line"><span>   - 채용 채널 (IT Works, TopCV, LinkedIn Vietnam)</span></span>
<span class="line"><span>   - 근로계약 주의사항 (베트남 노동법)</span></span>
<span class="line"><span>   - 사회보험, 건강보험, 실업보험 (회사 부담률)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 세무 &amp; 회계</span></span>
<span class="line"><span>   - 법인세: 20%</span></span>
<span class="line"><span>   - 부가세: 10%</span></span>
<span class="line"><span>   - 이전가격(TP) 규정 주의점</span></span>
<span class="line"><span>   - 한-베 이중과세방지협약 활용</span></span>
<span class="line"><span>   - 회계 기준 (VAS vs IFRS)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. 리스크 &amp; 주의사항</span></span>
<span class="line"><span>   - 법률/규제 변경 리스크 (빈번함)</span></span>
<span class="line"><span>   - 지식재산권 보호</span></span>
<span class="line"><span>   - 환율 리스크 (VND)</span></span>
<span class="line"><span>   - 문화 차이 (의사소통, 업무 스타일)</span></span>
<span class="line"><span>   - 한국-베트남 공휴일 차이</span></span>
<span class="line"><span></span></span>
<span class="line"><span>7. 실행 타임라인 (설립까지 3~4개월)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>면책: 최신 법률은 현지 법무법인/회계법인 확인 필요.</span></span></code></pre></div><h3 id="평가-포인트-4" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-4" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 법인 유형 비교의 정확성</li><li>[ ] 설립 절차의 순서와 소요기간 현실성</li><li>[ ] 도시별(하노이/호치민/다낭) 비교의 IT 관점</li><li>[ ] 베트남 개발자 시장의 현실적 연봉 범위</li><li>[ ] 이전가격(TP) 규정 인식</li><li>[ ] 이중과세방지협약 활용</li><li>[ ] 문화 차이 주의사항의 구체성</li></ul><hr><h2 id="ib-06-국제-전시회-참가-계획" tabindex="-1">IB-06. 국제 전시회 참가 계획 ⭐⭐ <a class="header-anchor" href="#ib-06-국제-전시회-참가-계획" aria-label="Permalink to &quot;IB-06. 국제 전시회 참가 계획 :star::star:&quot;">​</a></h2><h3 id="프롬프트-5" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-5" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>해외 전시회 참가 계획서를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>전시회: CES 2025 (미국 라스베이거스, 1/7~10)</span></span>
<span class="line"><span>우리: IoT 스타트업 &quot;센스랩&quot; (스마트홈 공기질 센서)</span></span>
<span class="line"><span>목적: 해외 바이어 발굴, 투자자 미팅, 브랜드 인지도</span></span>
<span class="line"><span>부스: 3m × 3m (스타트업 존)</span></span>
<span class="line"><span>예산: 8,000만원</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물: \`international/ces-2025-participation-plan.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 참가 목표 (SMART)</span></span>
<span class="line"><span>   - 바이어 미팅: 30건 이상</span></span>
<span class="line"><span>   - MOU 체결: 3건 이상</span></span>
<span class="line"><span>   - 미디어 노출: 5건 이상</span></span>
<span class="line"><span>   - 리드 수집: 200건</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 사전 준비 (D-90 ~ D-1)</span></span>
<span class="line"><span>   - D-90: 전시 등록, 부스 예약</span></span>
<span class="line"><span>   - D-60: 마케팅 자료 준비 (영문 카탈로그, 리플렛, 명함)</span></span>
<span class="line"><span>   - D-45: 타깃 바이어 리스트 작성 + 사전 미팅 요청</span></span>
<span class="line"><span>   - D-30: 부스 디자인 확정, 데모 준비, 홍보 영상</span></span>
<span class="line"><span>   - D-14: 물류 발송 (전시품, 인쇄물)</span></span>
<span class="line"><span>   - D-7: 현지 도착, 부스 설치, 리허설</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 부스 운영</span></span>
<span class="line"><span>   - 부스 디자인 콘셉트 (3×3 최대 활용)</span></span>
<span class="line"><span>   - 데모 시나리오 (3분 quick demo)</span></span>
<span class="line"><span>   - 부스 인력 배치 (3명: 영문 대응 2, 한국어 1)</span></span>
<span class="line"><span>   - 방문객 응대 프로세스 (인사→데모→명함 교환→팔로업 약속)</span></span>
<span class="line"><span>   - 리드 수집 도구 (명함 스캔 앱, QR코드)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 예산 배분</span></span>
<span class="line"><span>   - 부스 비용, 운송, 항공/숙박, 인쇄물, 식비, 통역, 기타</span></span>
<span class="line"><span>   - 8,000만원 내 상세 배분</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 사후 팔로업 (D+1 ~ D+30)</span></span>
<span class="line"><span>   - 수집 리드 분류 (Hot/Warm/Cold)</span></span>
<span class="line"><span>   - Hot 리드: 48시간 내 이메일 발송</span></span>
<span class="line"><span>   - 팔로업 이메일 템플릿 (영문, 3단계)</span></span>
<span class="line"><span>   - 미팅 결과 보고서 양식</span></span>
<span class="line"><span>   - 전시회 참가 성과 보고서 (경영진용)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. 체크리스트</span></span>
<span class="line"><span>   - 출국 전 / 전시 중 / 귀국 후 각각</span></span></code></pre></div><h3 id="평가-포인트-5" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-5" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] CES 참가 실무의 현실적 반영</li><li>[ ] 사전 바이어 미팅 확보 전략</li><li>[ ] 3×3 부스 최대 활용 디자인 아이디어</li><li>[ ] 데모 시나리오의 3분 내 임팩트</li><li>[ ] 예산 8,000만원의 합리적 배분</li><li>[ ] 사후 팔로업의 48시간 규칙</li><li>[ ] 전시회 ROI 측정 방법</li></ul><hr><h2 id="ib-07-크로스보더-협업-가이드" tabindex="-1">IB-07. 크로스보더 협업 가이드 ⭐⭐ <a class="header-anchor" href="#ib-07-크로스보더-협업-가이드" aria-label="Permalink to &quot;IB-07. 크로스보더 협업 가이드 :star::star:&quot;">​</a></h2><h3 id="프롬프트-6" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-6" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>다국적 팀과의 원격 협업 가이드를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>상황:</span></span>
<span class="line"><span>- 한국 본사 (개발 10명, 기획 3명)</span></span>
<span class="line"><span>- 베트남 오프쇼어 (개발 8명)</span></span>
<span class="line"><span>- 미국 고객 (PM 2명, 비즈니스 3명)</span></span>
<span class="line"><span>- 시차: 한국 +9, 베트남 +7, 미국 서부 -8 (한국 대비 -17시간)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물: \`international/cross-border-collaboration-guide.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 시차 관리</span></span>
<span class="line"><span>   - 3개 지역 시간대 맵 (겹치는 시간 식별)</span></span>
<span class="line"><span>   - 공통 가능 시간: 한국 22~24시 = 베트남 20~22시 = 미국 6~8시 (AM)</span></span>
<span class="line"><span>   - &quot;이건 너무 늦다&quot; → 현실적 대안:</span></span>
<span class="line"><span>     - 한국-베트남: 오전 미팅 (시차 2시간, 쉬움)</span></span>
<span class="line"><span>     - 한국-미국: 한국 아침 or 미국 아침 격주 교대</span></span>
<span class="line"><span>   - 비동기 커뮤니케이션 원칙 (모든 것을 문서로)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 커뮤니케이션 도구 &amp; 규칙</span></span>
<span class="line"><span>   - Slack: 채널 구조 설계 (프로젝트별, 긴급, 잡담)</span></span>
<span class="line"><span>   - 언어: 공용어 영어, 한-베 간 한국어 가능</span></span>
<span class="line"><span>   - 미팅: Google Meet (녹화 필수, 회의록 24시간 내 공유)</span></span>
<span class="line"><span>   - 문서: Notion (영문 기준, 한국어 주석 가능)</span></span>
<span class="line"><span>   - 긴급 연락: 전화 &gt; Slack DM &gt; 이메일</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 업무 프로세스</span></span>
<span class="line"><span>   - 스프린트: 2주 (플래닝: 월 아침 한-베 합동)</span></span>
<span class="line"><span>   - 코드 리뷰: PR 제출 → 12시간 내 리뷰 (시차 활용)</span></span>
<span class="line"><span>   - 핸드오프: 한국 퇴근 전 → 베트남/미국에 인수인계 메모</span></span>
<span class="line"><span>   - 의사결정: 비동기 투표 (Slack poll) + 48시간 데드라인</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 문화 차이 관리</span></span>
<span class="line"><span>   - 한국: 빠른 의사결정, 높은 컨텍스트 소통 (행간의 의미)</span></span>
<span class="line"><span>   - 베트남: 직접적 거부 어려움 (Yes가 진짜 Yes인지 확인)</span></span>
<span class="line"><span>   - 미국: 직접적 소통, 시간 엄수, 문서 중심</span></span>
<span class="line"><span>   - 각 문화 간 발생 가능한 오해 사례 5개 + 대처법</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 온보딩 (새 멤버 합류 시)</span></span>
<span class="line"><span>   - 각 지역별 온보딩 가이드</span></span>
<span class="line"><span>   - 버디 시스템 (다른 지역 멤버와 1:1 매칭)</span></span>
<span class="line"><span>   - 첫 주: 문화 OT, 도구 세팅, 소개 미팅</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. 팀 빌딩</span></span>
<span class="line"><span>   - 격월 비디오 소셜 (게임, 퀴즈 등 30분)</span></span>
<span class="line"><span>   - 연 1회 오프라인 모임 (워크숍)</span></span>
<span class="line"><span>   - &quot;Coffee Chat&quot; 랜덤 매칭 (주 1회)</span></span></code></pre></div><h3 id="평가-포인트-6" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-6" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] 시차 관리의 현실적 해법</li><li>[ ] 비동기 커뮤니케이션 원칙의 구체성</li><li>[ ] 한국-베트남-미국 3개 문화 차이의 정확한 이해</li><li>[ ] &quot;Yes가 진짜 Yes인지&quot; 같은 실전 인사이트</li><li>[ ] 핸드오프 메모의 구체적 형식</li><li>[ ] 팀 빌딩 아이디어의 실행 가능성</li><li>[ ] 전반적으로 실제 다국적 팀 운영 경험이 반영된 수준</li></ul><hr><h2 id="ib-08-fta-관세-활용-가이드" tabindex="-1">IB-08. FTA &amp; 관세 활용 가이드 ⭐⭐ <a class="header-anchor" href="#ib-08-fta-관세-활용-가이드" aria-label="Permalink to &quot;IB-08. FTA &amp; 관세 활용 가이드 :star::star:&quot;">​</a></h2><h3 id="프롬프트-7" tabindex="-1">프롬프트 <a class="header-anchor" href="#프롬프트-7" aria-label="Permalink to &quot;프롬프트&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>중소기업 수출 담당자를 위한 FTA 활용 가이드를 만들어줘.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>대상: FTA를 처음 활용하려는 수출 중소기업 담당자</span></span>
<span class="line"><span>목적: &quot;FTA 쓰면 관세가 줄어든다는데 어떻게 하는 거야?&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>산출물: \`international/fta-utilization-guide.md\`</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. FTA 기초 (비전문가 대상)</span></span>
<span class="line"><span>   - FTA가 뭔지 (한 줄)</span></span>
<span class="line"><span>   - 한국이 체결한 주요 FTA (미국, EU, 중국, 아세안, 일본...)</span></span>
<span class="line"><span>   - &quot;FTA를 쓰면 뭐가 좋은데?&quot; → 관세 절감 실제 사례</span></span>
<span class="line"><span>   - 예: 한-EU FTA로 화장품 관세 5% → 0% = 연 3천만원 절감</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. FTA 활용 절차 (Step by Step)</span></span>
<span class="line"><span>   - Step 1: 우리 제품의 HS Code 확인</span></span>
<span class="line"><span>   - Step 2: 수출국과의 FTA 확인 (관세율 조회)</span></span>
<span class="line"><span>   - Step 3: 원산지 결정 기준 확인 (세번변경, 부가가치)</span></span>
<span class="line"><span>   - Step 4: 원산지 증명서 발급 (기관 발급 vs 자율 발급)</span></span>
<span class="line"><span>   - Step 5: 바이어에게 원산지 증명서 전달</span></span>
<span class="line"><span>   - 각 단계: 구체적 방법, 사이트 링크, 소요 기간</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 원산지 관리</span></span>
<span class="line"><span>   - 원산지 확인서 (국내 원재료 공급업체로부터)</span></span>
<span class="line"><span>   - 원산지 소명서 작성법</span></span>
<span class="line"><span>   - 보관 의무 (5년)</span></span>
<span class="line"><span>   - 사후 검증 대비</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 실무 팁</span></span>
<span class="line"><span>   - &quot;HS Code를 잘못 적용하면 오히려 불이익&quot;</span></span>
<span class="line"><span>   - 누적 원산지 규정 활용법</span></span>
<span class="line"><span>   - 중간재 수입 시 FTA 연계 활용</span></span>
<span class="line"><span>   - 관세사 선택 기준</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 자주 하는 실수 TOP 5</span></span>
<span class="line"><span>   - 원산지 증명서 미발급/미첨부</span></span>
<span class="line"><span>   - HS Code 오류</span></span>
<span class="line"><span>   - FTA별 원산지 기준 혼동</span></span>
<span class="line"><span>   - 보관 의무 미이행</span></span>
<span class="line"><span>   - 인코텀즈와 FTA 혼동</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. 도움받을 수 있는 곳</span></span>
<span class="line"><span>   - 관세청, KOTRA, FTA 종합지원센터</span></span>
<span class="line"><span>   - 무료 컨설팅 신청 방법</span></span></code></pre></div><h3 id="평가-포인트-7" tabindex="-1">평가 포인트 <a class="header-anchor" href="#평가-포인트-7" aria-label="Permalink to &quot;평가 포인트&quot;">​</a></h3><ul><li>[ ] FTA 기초 설명의 접근성 (비전문가 이해)</li><li>[ ] HS Code 조회 방법의 구체성</li><li>[ ] 원산지 결정 기준의 정확성</li><li>[ ] &quot;관세 절감 실제 사례&quot;의 계산 정확성</li><li>[ ] 자주 하는 실수의 현실성</li><li>[ ] 지원 기관 정보의 정확성</li><li>[ ] 전체적으로 &quot;처음 수출하는 사람&quot;이 따라할 수 있는 수준</li></ul>`,50)])])}const b=s(i,[["render",e]]);export{u as __pageData,b as default};
